import React from 'react';

export const Button = ({ 
    children, 
    onClick, 
    variant = 'primary', 
    className = '', 
    title = '',
    ...props 
}) => {
    const variants = {
        primary: 'bg-primary hover:bg-primary-hover text-white shadow-neon-primary px-4 py-2 rounded-lg text-sm font-semibold transition-all duration-300 active:scale-95',
        secondary: 'bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700 px-4 py-2 rounded-lg text-sm font-semibold transition-all duration-300 active:scale-95',
        dangerIcon: 'p-1.5 text-slate-500 hover:text-rose-400 hover:bg-rose-400/10 rounded-md transition-all duration-300',
        ghost: 'text-slate-400 hover:text-white hover:bg-slate-800 p-2 rounded-lg transition-all'
    };

    return (
        <button
            onClick={onClick}
            className={`${variants[variant]} ${className} flex items-center justify-center gap-2`}
            title={title}
            {...props}
        >
            {children}
        </button>
    );
};
